"""PackRuntime - validate and prepare workspace for building."""

import logging
import shutil
from pathlib import Path
from typing import Any, Dict, Optional

from agentcube.services.metadata_service import AgentMetadata, MetadataService

logger = logging.getLogger(__name__)


class PackRuntime:
    """Runtime for packing agent workspaces."""

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose
        self.metadata_service = MetadataService(verbose=verbose)

    def pack(self, workspace_path: Path, **options: Any) -> Dict[str, Any]:
        """Pack the workspace and return pack results."""
        workspace_path = workspace_path.resolve()

        self._validate_workspace_structure(workspace_path)

        metadata = self._load_or_create_metadata(workspace_path, options)

        self._apply_option_overrides(metadata, options)

        self._validate_language_compatibility(workspace_path, metadata)

        self._process_dependencies(workspace_path, metadata)

        dockerfile_path = self._generate_dockerfile(workspace_path, metadata)

        self._update_pack_metadata(workspace_path, metadata, dockerfile_path)

        return {
            "agent_name": metadata.agent_name,
            "workspace_path": str(workspace_path),
            "metadata_path": str(workspace_path / "agent_metadata.yaml"),
            "dockerfile_path": str(dockerfile_path) if dockerfile_path else None,
        }

    def _validate_workspace_structure(self, workspace_path: Path) -> None:
        """Validate that the workspace exists and is a directory."""
        if not workspace_path.exists():
            raise ValueError(f"Workspace directory does not exist: {workspace_path}")

        if not workspace_path.is_dir():
            raise ValueError(f"Workspace path is not a directory: {workspace_path}")

    def _load_or_create_metadata(self, workspace_path: Path, options: Dict[str, Any]) -> AgentMetadata:
        """Load existing metadata or create new metadata."""
        try:
            return self.metadata_service.load_metadata(workspace_path)
        except FileNotFoundError:
            agent_name = options.get("agent_name") or workspace_path.name
            language = options.get("language", "python")
            entrypoint = options.get("entrypoint") or self._infer_entrypoint(workspace_path, language)
            port = options.get("port", 8080)

            return AgentMetadata(
                agent_name=agent_name,
                language=language,
                entrypoint=entrypoint,
                port=port,
            )

    def _apply_option_overrides(self, metadata: AgentMetadata, options: Dict[str, Any]) -> AgentMetadata:
        """Apply CLI option overrides to metadata."""
        if options.get("agent_name"):
            metadata.agent_name = options["agent_name"]
        if options.get("language"):
            metadata.language = options["language"]
        if options.get("entrypoint"):
            metadata.entrypoint = options["entrypoint"]
        if options.get("port"):
            metadata.port = options["port"]
        if options.get("build_mode"):
            metadata.build_mode = options["build_mode"]
        if options.get("description"):
            metadata.description = options["description"]
        if options.get("workload_manager_url"):
            metadata.workload_manager_url = options["workload_manager_url"]
        if options.get("router_url"):
            metadata.router_url = options["router_url"]

        return metadata

    def _validate_language_compatibility(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Validate workspace structure matches the declared language."""
        language = metadata.language.lower()

        if language == "python":
            self._validate_python_compatibility(workspace_path)
        elif language == "java":
            self._validate_java_compatibility(workspace_path)
        else:
            logger.warning(f"Unknown language '{language}', skipping compatibility check")

    def _validate_python_compatibility(self, workspace_path: Path) -> None:
        """Validate Python workspace has Python files."""
        py_files = list(workspace_path.glob("*.py"))
        if not py_files:
            raise ValueError("No Python files found in workspace")

    def _validate_java_compatibility(self, workspace_path: Path) -> None:
        """Validate Java workspace has pom.xml."""
        pom_file = workspace_path / "pom.xml"
        if not pom_file.exists():
            raise ValueError("No pom.xml found in Java workspace")

    def _process_dependencies(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Process language-specific dependencies."""
        language = metadata.language.lower()

        if language == "python":
            self._process_python_dependencies(workspace_path)
        elif language == "java":
            self._process_java_dependencies(workspace_path)

    def _process_python_dependencies(self, workspace_path: Path) -> None:
        """Process Python dependencies."""
        req_file = workspace_path / "requirements.txt"
        if not req_file.exists():
            logger.info("No requirements.txt found, creating empty file")
            req_file.touch()

    def _process_java_dependencies(self, workspace_path: Path) -> None:
        """Process Java dependencies - handled by Maven."""
        pass

    def _generate_dockerfile(self, workspace_path: Path, metadata: AgentMetadata) -> Optional[Path]:
        """Generate Dockerfile based on language."""
        dockerfile_path = workspace_path / "Dockerfile"

        language = metadata.language.lower()

        if language == "python":
            content = self._generate_python_dockerfile(metadata)
        elif language == "java":
            content = self._generate_java_dockerfile(metadata)
        else:
            logger.warning(f"Cannot generate Dockerfile for language: {language}")
            return None

        dockerfile_path.write_text(content)
        return dockerfile_path

    def _generate_python_dockerfile(self, metadata: AgentMetadata) -> str:
        """Generate Dockerfile for Python agent."""
        return f'''FROM python:3.12-slim

WORKDIR /app

COPY requirements.txt .
RUN pip install --no-cache-dir -r requirements.txt

COPY . .

EXPOSE {metadata.port}

CMD {metadata.entrypoint}
'''

    def _generate_java_dockerfile(self, metadata: AgentMetadata) -> str:
        """Generate Dockerfile for Java agent."""
        return f'''FROM maven:3.9-eclipse-temurin-21 AS build

WORKDIR /app

COPY pom.xml .
RUN mvn dependency:go-offline

COPY src ./src
RUN mvn package -DskipTests

FROM eclipse-temurin:21-jre

WORKDIR /app

COPY --from=build /app/target/*.jar app.jar

EXPOSE {metadata.port}

CMD {metadata.entrypoint}
'''

    def _update_pack_metadata(self, workspace_path: Path, metadata: AgentMetadata, dockerfile_path: Optional[Path]) -> None:
        """Update metadata with pack results."""
        metadata.image = {
            "dockerfile_path": str(dockerfile_path) if dockerfile_path else None,
        }
        self.metadata_service.save_metadata(workspace_path, metadata)

    def _infer_entrypoint(self, workspace_path: Path, language: str) -> str:
        """Infer default entrypoint from workspace structure."""
        language = language.lower()

        if language == "python":
            main_py = workspace_path / "main.py"
            if main_py.exists():
                return '["python", "main.py"]'
            app_py = workspace_path / "app.py"
            if app_py.exists():
                return '["python", "app.py"]'
            return '["python", "main.py"]'

        elif language == "java":
            return '["java", "-jar", "app.jar"]'

        return '["python", "main.py"]'

"""BuildRuntime - build container images from packaged workspaces."""

import logging
import os
import time
from pathlib import Path
from typing import Any, Dict, Optional

from agentcube.services.docker_service import DockerService
from agentcube.services.metadata_service import AgentMetadata, MetadataService

logger = logging.getLogger(__name__)


class BuildRuntime:
    """Runtime for building container images."""

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose
        self.docker_service = DockerService(verbose=verbose)
        self.metadata_service = MetadataService(verbose=verbose)

    def build(self, workspace_path: Path, **options: Any) -> Dict[str, Any]:
        """Build container image from workspace."""
        workspace_path = workspace_path.resolve()

        self._validate_build_prerequisites(workspace_path)

        metadata = self.metadata_service.load_metadata(workspace_path)

        original_version = metadata.version
        new_version = self._increment_version(workspace_path, metadata)

        build_mode = metadata.build_mode or "local"

        try:
            if build_mode == "local":
                result = self._build_local(workspace_path, metadata, options)
            else:
                result = self._build_cloud(workspace_path, metadata, options)

            self._update_build_metadata(workspace_path, metadata, result, new_version)

            return result
        except Exception as e:
            if original_version:
                metadata.version = original_version
                self.metadata_service.save_metadata(workspace_path, metadata)
            raise

    def _increment_version(self, workspace_path: Path, metadata: AgentMetadata) -> str:
        """Increment version and return new version string."""
        current = metadata.version

        if not current:
            return "0.1.0"

        if current.startswith("v"):
            current = current[1:]

        parts = current.split(".")

        if len(parts) == 3:
            try:
                major, minor, patch = int(parts[0]), int(parts[1]), int(parts[2])
                new_version = f"{major}.{minor}.{patch + 1}"
                metadata.version = new_version
                return new_version
            except ValueError:
                pass

        return f"{current}-1"

    def _validate_build_prerequisites(self, workspace_path: Path) -> None:
        """Validate build prerequisites."""
        if not workspace_path.exists():
            raise ValueError(f"Workspace does not exist: {workspace_path}")

        dockerfile = workspace_path / "Dockerfile"
        if not dockerfile.exists():
            raise ValueError("Dockerfile not found. Run 'pack' first.")

        if not self.docker_service.check_docker_available():
            raise RuntimeError("Docker is not available or not running")

    def _build_local(self, workspace_path: Path, metadata: AgentMetadata, options: Dict[str, Any]) -> Dict[str, Any]:
        """Build image locally using Docker."""
        dockerfile_path = workspace_path / "Dockerfile"

        image_name = metadata.agent_name.lower().replace("_", "-").replace(" ", "-")
        tag = metadata.version or "latest"

        build_args = {}
        if options.get("proxy"):
            build_args["HTTP_PROXY"] = options["proxy"]
            build_args["HTTPS_PROXY"] = options["proxy"]

        result = self.docker_service.build_image(
            dockerfile_path=dockerfile_path,
            context_path=workspace_path,
            image_name=image_name,
            tag=tag,
            build_args=build_args if build_args else None,
        )

        return {
            "image_name": f"{image_name}:{tag}",
            "image_id": result.get("image_id", ""),
            "image_size": result.get("image_size", ""),
            "build_time": result.get("build_time", ""),
        }

    def _build_cloud(self, workspace_path: Path, metadata: AgentMetadata, options: Dict[str, Any]) -> Dict[str, Any]:
        """Build image in cloud (placeholder for cloud build implementation)."""
        raise NotImplementedError("Cloud build is not yet implemented. Use --build-mode local.")

    def _update_build_metadata(self, workspace_path: Path, metadata: AgentMetadata, build_result: Dict[str, str], tag: str = "latest") -> None:
        """Update metadata with build results."""
        if not metadata.image:
            metadata.image = {}

        metadata.image.update({
            "name": build_result.get("image_name", ""),
            "id": build_result.get("image_id", ""),
            "size": build_result.get("image_size", ""),
            "build_time": build_result.get("build_time", ""),
            "tag": tag,
        })

        self.metadata_service.save_metadata(workspace_path, metadata)

"""StatusRuntime - get agent status."""

import logging
from pathlib import Path
from typing import Any, Dict, Optional

from agentcube.services.agentcube_provider import AgentCubeProvider
from agentcube.services.k8s_provider import KubernetesProvider
from agentcube.services.metadata_service import MetadataService

logger = logging.getLogger(__name__)


class StatusRuntime:
    """Runtime for checking agent status."""

    def __init__(self, verbose: bool = False, provider: str = "agentcube") -> None:
        self.verbose = verbose
        self.provider = provider
        self.metadata_service = MetadataService(verbose=verbose)

    def get_status(self, workspace_path: Path, provider: Optional[str] = None) -> Dict[str, Any]:
        """Get the status of the agent."""
        workspace_path = workspace_path.resolve()

        if not workspace_path.exists():
            raise ValueError(f"Workspace does not exist: {workspace_path}")

        try:
            metadata = self.metadata_service.load_metadata(workspace_path)
        except FileNotFoundError:
            return {"status": "not_published"}

        if not metadata.agent_id:
            return {"status": "not_published"}

        actual_provider = provider or self.provider

        if actual_provider == "agentcube":
            return self._get_cr_k8s_status(metadata)
        else:
            return self._get_k8s_status(metadata)

    def _get_k8s_status(self, metadata: Any) -> Dict[str, Any]:
        """Get status from Kubernetes Deployment."""
        k8s_deployment = metadata.k8s_deployment

        if not k8s_deployment:
            return {"status": "not_published"}

        namespace = k8s_deployment.get("namespace", "default")

        try:
            k8s_provider = KubernetesProvider(namespace=namespace, verbose=self.verbose)
            status_info = k8s_provider.get_agent_status(metadata.agent_name)

            return {
                "status": status_info.get("status", "unknown"),
                "agent_name": metadata.agent_name,
                "namespace": namespace,
                "replicas": status_info.get("replicas"),
                "available_replicas": status_info.get("available_replicas"),
                "endpoint": metadata.agent_endpoint,
            }
        except Exception as e:
            return {"status": "error", "error": str(e)}

    def _get_cr_k8s_status(self, metadata: Any) -> Dict[str, Any]:
        """Get status from AgentRuntime CR."""
        k8s_deployment = metadata.k8s_deployment

        if not k8s_deployment:
            return {"status": "not_published"}

        namespace = k8s_deployment.get("namespace", "default")

        try:
            agentcube_provider = AgentCubeProvider(namespace=namespace, verbose=self.verbose)
            cr_object = agentcube_provider.get_agent_runtime(
                name=metadata.agent_name,
                namespace=namespace,
            )

            if not cr_object:
                return {"status": "not_found_in_k8s"}

            cr_status = cr_object.get("status", {})

            if cr_status:
                return {
                    "status": cr_status.get("status", "created_no_status"),
                    "agent_name": metadata.agent_name,
                    "namespace": namespace,
                    "endpoint": cr_status.get("agentEndpoint", metadata.agent_endpoint),
                }
            else:
                return {
                    "status": "created_no_status",
                    "agent_name": metadata.agent_name,
                    "namespace": namespace,
                }
        except Exception as e:
            return {"status": "error", "error": str(e)}

"""MetadataService and AgentMetadata for agent configuration management."""

import logging
from pathlib import Path
from typing import Any, Dict, Optional

import yaml
from pydantic import BaseModel, field_validator

logger = logging.getLogger(__name__)


class AgentMetadata(BaseModel):
    """Agent metadata configuration."""

    agent_name: str
    description: Optional[str] = None
    language: str = "python"
    entrypoint: str
    port: int = 8080
    build_mode: str = "local"
    region: Optional[str] = None
    version: Optional[str] = None
    image: Optional[Dict[str, Any]] = None
    auth: Optional[Dict[str, Any]] = None
    requirements_file: Optional[str] = "requirements.txt"
    registry_url: Optional[str] = ""
    registry_username: Optional[str] = ""
    registry_password: Optional[str] = ""
    agent_endpoint: Optional[str] = None
    workload_manager_url: Optional[str] = None
    router_url: Optional[str] = None
    readiness_probe_path: Optional[str] = None
    readiness_probe_port: Optional[int] = None
    agent_id: Optional[str] = None
    session_id: Optional[str] = None
    k8s_deployment: Optional[Dict[str, Any]] = None

    @field_validator("language")
    @classmethod
    def validate_language(cls, v: str) -> str:
        v = v.lower()
        if v not in ("python", "java"):
            raise ValueError(f"Unsupported language: {v}. Must be 'python' or 'java'")
        return v

    @field_validator("build_mode")
    @classmethod
    def validate_build_mode(cls, v: str) -> str:
        v = v.lower()
        if v not in ("local", "cloud"):
            raise ValueError(f"Unsupported build_mode: {v}. Must be 'local' or 'cloud'")
        return v

    @field_validator("port")
    @classmethod
    def validate_port(cls, v: int) -> int:
        if v < 1 or v > 65535:
            raise ValueError(f"Port must be between 1 and 65535, got {v}")
        return v


class MetadataService:
    """Service for managing agent metadata."""

    METADATA_FILENAMES = ["agent_metadata.yaml", "agent.yaml", "metadata.yaml"]

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose

    def load_metadata(self, workspace_path: Path) -> AgentMetadata:
        """Load metadata from workspace."""
        workspace_path = workspace_path.resolve()

        for filename in self.METADATA_FILENAMES:
            metadata_path = workspace_path / filename
            if metadata_path.exists():
                return self._load_metadata_file(metadata_path)

        raise FileNotFoundError(f"No metadata file found in {workspace_path}")

    def _load_metadata_file(self, metadata_path: Path) -> AgentMetadata:
        """Load metadata from a specific file."""
        with open(metadata_path, "r") as f:
            data = yaml.safe_load(f)

        return AgentMetadata(**data)

    def save_metadata(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Save metadata to workspace."""
        workspace_path = workspace_path.resolve()
        metadata_path = workspace_path / "agent_metadata.yaml"

        data = metadata.model_dump(exclude_none=True)

        with open(metadata_path, "w") as f:
            yaml.dump(data, f, default_flow_style=False, indent=2, sort_keys=False)

    def update_metadata(self, workspace_path: Path, updates: Dict[str, Any]) -> AgentMetadata:
        """Update metadata with new values."""
        metadata = self.load_metadata(workspace_path)

        for key, value in updates.items():
            if hasattr(metadata, key):
                setattr(metadata, key, value)

        self.save_metadata(workspace_path, metadata)
        return metadata

    def validate_workspace(self, workspace_path: Path) -> bool:
        """Validate workspace structure."""
        workspace_path = workspace_path.resolve()

        if not workspace_path.exists():
            return False

        if not workspace_path.is_dir():
            return False

        try:
            metadata = self.load_metadata(workspace_path)

            if metadata.language == "python":
                self._validate_python_workspace(workspace_path, metadata)
            elif metadata.language == "java":
                self._validate_java_workspace(workspace_path, metadata)

            return True
        except Exception as e:
            logger.error(f"Workspace validation failed: {e}")
            return False

    def _validate_python_workspace(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Validate Python workspace."""
        py_files = list(workspace_path.glob("*.py"))
        if not py_files:
            raise ValueError("No Python files found in workspace")

    def _validate_java_workspace(self, workspace_path: Path, metadata: AgentMetadata) -> None:
        """Validate Java workspace."""
        pom_file = workspace_path / "pom.xml"
        if not pom_file.exists():
            raise ValueError("No pom.xml found in Java workspace")

"""DockerService for building and pushing container images."""

import logging
import time
from pathlib import Path
from typing import Any, Dict, Optional

logger = logging.getLogger(__name__)


class DockerService:
    """Service for Docker operations."""

    def __init__(self, verbose: bool = False) -> None:
        self.verbose = verbose
        self._client = None

    @property
    def client(self):
        """Lazy load Docker client."""
        if self._client is None:
            try:
                import docker
                self._client = docker.from_env()
            except Exception as e:
                logger.error(f"Failed to initialize Docker client: {e}")
                raise
        return self._client

    def check_docker_available(self) -> bool:
        """Check if Docker is available and running."""
        try:
            client = self.client
            client.ping()
            return True
        except Exception:
            return False

    def build_image(
        self,
        dockerfile_path: Path,
        context_path: Path,
        image_name: str,
        tag: str = "latest",
        build_args: Optional[Dict[str, str]] = None,
    ) -> Dict[str, str]:
        """Build a Docker image."""
        start_time = time.time()

        full_name = f"{image_name}:{tag}"

        build_kwargs = {
            "path": str(context_path),
            "dockerfile": str(dockerfile_path),
            "tag": full_name,
            "rm": True,
            "forcerm": True,
        }

        if build_args:
            build_kwargs["buildargs"] = build_args

        if self.verbose:
            logger.info(f"Building image: {full_name}")

        try:
            image, build_logs = self.client.images.build(**build_kwargs)

            if self.verbose:
                for log in build_logs:
                    if "stream" in log:
                        logger.info(log["stream"].strip())

            build_time = time.time() - start_time

            image_info = self._get_image_info(image.id)

            return {
                "image_name": full_name,
                "image_id": image.id[:12],
                "image_size": image_info.get("size", "unknown"),
                "build_time": f"{build_time:.2f}s",
            }
        except Exception as e:
            logger.error(f"Failed to build image: {e}")
            raise

    def get_image_info(self, image_name: str) -> Dict[str, str]:
        """Get information about an image."""
        return self._get_image_info(image_name)

    def _get_image_info(self, image_name_or_id: str) -> Dict[str, str]:
        """Internal method to get image info."""
        try:
            image = self.client.images.get(image_name_or_id)
            size_bytes = image.attrs.get("Size", 0)

            return {
                "id": image.id[:12],
                "size": self._format_size(size_bytes),
                "tags": ", ".join(image.tags) if image.tags else "none",
            }
        except Exception as e:
            logger.warning(f"Failed to get image info: {e}")
            return {"id": "unknown", "size": "unknown", "tags": "none"}

    def _format_size(self, size_bytes: int) -> str:
        """Format size in bytes to human-readable string."""
        for unit in ["B", "KB", "MB", "GB", "TB"]:
            if size_bytes < 1024:
                return f"{size_bytes:.1f} {unit}"
            size_bytes /= 1024
        return f"{size_bytes:.1f} PB"

    def push_image(
        self,
        image_name: str,
        registry_url: Optional[str] = None,
        username: Optional[str] = None,
        password: Optional[str] = None,
    ) -> Dict[str, str]:
        """Push image to a registry."""
        start_time = time.time()

        if registry_url and username and password:
            self._docker_login_sdk(registry_url, username, password)

        if registry_url:
            full_image_name = f"{registry_url}/{image_name}"
            self._tag_image_sdk(image_name, full_image_name)
            image_name = full_image_name

        if self.verbose:
            logger.info(f"Pushing image: {image_name}")

        try:
            push_logs = self.client.images.push(image_name, stream=True, decode=True)

            if self.verbose:
                for log in push_logs:
                    if "status" in log:
                        logger.info(log["status"])

            push_time = time.time() - start_time

            return {
                "pushed_image": image_name,
                "push_time": f"{push_time:.2f}s",
            }
        except Exception as e:
            logger.error(f"Failed to push image: {e}")
            raise

    def _docker_login_sdk(self, registry: Optional[str], username: str, password: str) -> None:
        """Login to Docker registry."""
