"""KubernetesProvider for deploying agents as Deployment and Service."""

import logging
import re
import time
from typing import Any, Dict, Optional

logger = logging.getLogger(__name__)


class KubernetesProvider:
    """Provider for Kubernetes deployments."""

    def __init__(
        self,
        namespace: str = "default",
        verbose: bool = False,
        kubeconfig: Optional[str] = None,
    ) -> None:
        self.namespace = namespace
        self.verbose = verbose
        self.kubeconfig = kubeconfig
        self._api_client = None
        self._apps_api = None
        self._core_api = None

    def _load_kube_config(self):
        """Load Kubernetes configuration."""
        try:
            from kubernetes import config
            if self.kubeconfig:
                config.load_kube_config(config_file=self.kubeconfig)
            else:
                try:
                    config.load_incluster_config()
                except:
                    config.load_kube_config()
        except ImportError:
            raise ImportError(
                "kubernetes package not installed. "
                "Install with: pip install kubernetes"
            )

    @property
    def api_client(self):
        """Get API client."""
        if self._api_client is None:
            self._load_kube_config()
            from kubernetes import client
            self._api_client = client
        return self._api_client

    @property
    def apps_api(self):
        """Get AppsV1Api."""
        if self._apps_api is None:
            self._apps_api = self.api_client.AppsV1Api()
        return self._apps_api

    @property
    def core_api(self):
        """Get CoreV1Api."""
        if self._core_api is None:
            self._core_api = self.api_client.CoreV1Api()
        return self._core_api

    def _ensure_namespace(self) -> None:
        """Ensure namespace exists."""
        try:
            self.core_api.read_namespace(self.namespace)
        except Exception:
            from kubernetes import client
            namespace_body = client.V1Namespace(
                metadata=client.V1ObjectMeta(name=self.namespace)
            )
            self.core_api.create_namespace(namespace_body)
            if self.verbose:
                logger.info(f"Created namespace: {self.namespace}")

    def deploy_agent(
        self,
        agent_name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str] = None,
        replicas: int = 1,
        node_port: Optional[int] = None,
        env_vars: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        """Deploy agent as Deployment and Service."""
        self._ensure_namespace()

        sanitized_name = self._sanitize_name(agent_name)

        deployment_result = self._create_deployment(
            name=sanitized_name,
            image_url=image_url,
            port=port,
            entrypoint=entrypoint,
            replicas=replicas,
            env_vars=env_vars,
        )

        service_result = self._create_service(
            name=sanitized_name,
            port=port,
            node_port=node_port,
        )

        return {
            "agent_id": sanitized_name,
            "deployment_name": sanitized_name,
            "service_name": sanitized_name,
            "namespace": self.namespace,
            "replicas": replicas,
            "container_port": port,
            "node_port": service_result.get("node_port"),
            "endpoint": f"http://localhost:{service_result.get('node_port', port)}",
        }

    def _create_deployment(
        self,
        name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str],
        replicas: int,
        env_vars: Optional[Dict[str, str]],
    ) -> Dict[str, Any]:
        """Create or update Deployment."""
        from kubernetes import client

        labels = {"app": name}

        env_list = []
        if env_vars:
            for key, value in env_vars.items():
                env_list.append(client.V1EnvVar(name=key, value=value))

        container = client.V1Container(
            name=name,
            image=image_url,
            ports=[client.V1ContainerPort(container_port=port)],
            env=env_list if env_list else None,
        )

        if entrypoint:
            import json
            try:
                cmd = json.loads(entrypoint)
                container.command = cmd
            except json.JSONDecodeError:
                container.command = [entrypoint]

        pod_spec = client.V1PodSpec(
            containers=[container],
            restart_policy="Always",
        )

        template = client.V1PodTemplateSpec(
            metadata=client.V1ObjectMeta(labels=labels),
            spec=pod_spec,
        )

        spec = client.V1DeploymentSpec(
            replicas=replicas,
            selector=client.V1LabelSelector(match_labels=labels),
            template=template,
        )

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=name, namespace=self.namespace),
            spec=spec,
        )

        try:
            self.apps_api.read_namespaced_deployment(name, self.namespace)
            self.apps_api.patch_namespaced_deployment(name, self.namespace, deployment)
            if self.verbose:
                logger.info(f"Updated deployment: {name}")
        except Exception:
            self.apps_api.create_namespaced_deployment(self.namespace, deployment)
            if self.verbose:
                logger.info(f"Created deployment: {name}")

        return {"name": name, "namespace": self.namespace}

    def _create_service(self, name: str, port: int, node_port: Optional[int]) -> Dict[str, Any]:
        """Create or update Service."""
        from kubernetes import client

        labels = {"app": name}

        service_type = "NodePort" if node_port else "ClusterIP"

        port_spec = client.V1ServicePort(
            port=port,
            target_port=port,
            node_port=node_port if node_port else None,
        )

        spec = client.V1ServiceSpec(
            type=service_type,
            selector=labels,
            ports=[port_spec],
        )

        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=name, namespace=self.namespace),
            spec=spec,
        )

        try:
            existing = self.core_api.read_namespaced_service(name, self.namespace)
            result = self.core_api.patch_namespaced_service(name, self.namespace, service)
            if self.verbose:
                logger.info(f"Updated service: {name}")
        except Exception:
            result = self.core_api.create_namespaced_service(self.namespace, service)
            if self.verbose:
                logger.info(f"Created service: {name}")

        actual_node_port = None
        if service_type == "NodePort":
            actual_node_port = result.spec.ports[0].node_port

        return {"name": name, "namespace": self.namespace, "node_port": actual_node_port}

    def wait_for_deployment_ready(self, name: str, timeout: int = 120) -> None:
        """Wait for deployment to be ready."""
        start_time = time.time()

        while time.time() - start_time < timeout:
            try:
                deployment = self.apps_api.read_namespaced_deployment(name, self.namespace)

                if deployment.status.ready_replicas == deployment.spec.replicas:
                    if self.verbose:
                        logger.info(f"Deployment {name} is ready")
                    return

                if self.verbose:
                    logger.info(
                        f"Waiting for deployment {name}: "
                        f"{deployment.status.ready_replicas or 0}/{deployment.spec.replicas}"
                    )
            except Exception as e:
                if self.verbose:
                    logger.warning(f"Error checking deployment: {e}")

            time.sleep(2)

        raise TimeoutError(f"Deployment {name} not ready after {timeout} seconds")

    def get_agent_status(self, agent_name: str) -> Dict[str, Any]:
        """Get status of the agent deployment."""
        try:
            deployment = self.apps_api.read_namespaced_deployment(agent_name, self.namespace)

            return {
                "status": "running" if deployment.status.ready_replicas == deployment.spec.replicas else "pending",
                "replicas": deployment.spec.replicas,
                "available_replicas": deployment.status.available_replicas or 0,
                "ready_replicas": deployment.status.ready_replicas or 0,
            }
        except Exception as e:
            return {"status": "error", "error": str(e)}

    def delete_agent(self, agent_name: str) -> Dict[str, Any]:
        """Delete agent deployment and service."""
        errors = []

        try:
            self.apps_api.delete_namespaced_deployment(agent_name, self.namespace)
            if self.verbose:
                logger.info(f"Deleted deployment: {agent_name}")
        except Exception as e:
            if "404" not in str(e):
                errors.append(f"deployment: {e}")

        try:
            self.core_api.delete_namespaced_service(agent_name, self.namespace)
            if self.verbose:
                logger.info(f"Deleted service: {agent_name}")
        except Exception as e:
            if "404" not in str(e):
                errors.append(f"service: {e}")

        return {
            "status": "deleted" if not errors else "partial",
            "deployment_name": agent_name,
            "namespace": self.namespace,
            "errors": errors if errors else None,
        }

    def _sanitize_name(self, name: str) -> str:
        """Sanitize name for Kubernetes resource."""
        name = name.lower()
        name = re.sub(r"[^a-z0-9-]", "-", name)
        name = re.sub(r"-+", "-", name)
        name = name.strip("-")

        if len(name) > 63:
            name = name[:63].rstrip("-")

        return name

