import logging
import os
import re
from typing import Any, Dict, Optional

logger = logging.getLogger(__name__)


class AgentCubeProvider:
    """Provider for AgentCube AgentRuntime CRs."""

    CR_GROUP = "runtime.agentcube.volcano.sh"
    CR_VERSION = "v1alpha1"
    CR_PLURAL = "agentruntimes"

    def __init__(
        self,
        namespace: str = "default",
        verbose: bool = False,
        kubeconfig: Optional[str] = None,
    ) -> None:
        self.namespace = namespace
        self.verbose = verbose
        self.kubeconfig = kubeconfig
        self._api_client = None
        self._custom_api = None

    def _load_kube_config(self):
        """Load Kubernetes configuration."""
        try:
            from kubernetes import config
            if self.kubeconfig:
                config.load_kube_config(config_file=self.kubeconfig)
            else:
                try:
                    config.load_incluster_config()
                except:
                    config.load_kube_config()
        except ImportError:
            raise ImportError(
                "kubernetes package not installed. "
                "Install with: pip install kubernetes"
            )

    @property
    def api_client(self):
        """Get API client."""
        if self._api_client is None:
            self._load_kube_config()
            from kubernetes import client
            self._api_client = client
        return self._api_client

    @property
    def custom_api(self):
        """Get CustomObjectsApi."""
        if self._custom_api is None:
            self._custom_api = self.api_client.CustomObjectsApi()
        return self._custom_api

    def _ensure_namespace(self) -> None:
        """Ensure namespace exists."""
        try:
            core_api = self.api_client.CoreV1Api()
            core_api.read_namespace(self.namespace)
        except Exception:
            namespace_body = self.api_client.V1Namespace(
                metadata=self.api_client.V1ObjectMeta(name=self.namespace)
            )
            core_api.create_namespace(namespace_body)
            if self.verbose:
                logger.info(f"Created namespace: {self.namespace}")

    def deploy_agent_runtime(
        self,
        agent_name: str,
        image_url: str,
        port: int,
        entrypoint: Optional[str] = None,
        env_vars: Optional[Dict[str, str]] = None,
        workload_manager_url: Optional[str] = None,
        router_url: Optional[str] = None,
        readiness_probe_path: Optional[str] = None,
        readiness_probe_port: Optional[int] = None,
    ) -> Dict[str, Any]:
        """Deploy agent as AgentRuntime CR."""
        self._ensure_namespace()

        sanitized_name = self._sanitize_name(agent_name)

        final_env = env_vars or {}

        if workload_manager_url and "WORKLOAD_MANAGER_URL" not in final_env:
            final_env["WORKLOAD_MANAGER_URL"] = workload_manager_url
        if router_url and "ROUTER_URL" not in final_env:
            final_env["ROUTER_URL"] = router_url

        cr_body = {
            "apiVersion": f"{self.CR_GROUP}/{self.CR_VERSION}",
            "kind": "AgentRuntime",
            "metadata": {
                "name": sanitized_name,
                "namespace": self.namespace,
            },
            "spec": {
                "sessionTimeout": "15m",
                "maxSessionDuration": "8h",
                "targetPort": [
                    {
                        "port": port,
                        "protocol": "HTTP",
                    }
                ],
                "podTemplate": {
                    "spec": {
                        "containers": [
                            {
                                "name": sanitized_name,
                                "image": image_url,
                                "ports": [
                                    {
                                        "containerPort": port,
                                    }
                                ],
                                "env": [
                                    {"name": k, "value": v} for k, v in final_env.items()
                                ],
                            }
                        ],
                        "imagePullSecrets": [
                            {"name": "default-secret"}
                        ],
                    }
                },
            },
        }

        if entrypoint:
            import json
            try:
                cmd = json.loads(entrypoint)
                cr_body["spec"]["podTemplate"]["spec"]["containers"][0]["command"] = cmd
            except json.JSONDecodeError:
                cr_body["spec"]["podTemplate"]["spec"]["containers"][0]["command"] = [entrypoint]

        if readiness_probe_path and readiness_probe_port:
            cr_body["spec"]["podTemplate"]["spec"]["containers"][0]["readinessProbe"] = {
                "httpGet": {
                    "path": readiness_probe_path,
                    "port": readiness_probe_port,
                },
                "initialDelaySeconds": 5,
                "periodSeconds": 10,
            }

        try:
            self.custom_api.get_namespaced_custom_object(
                group=self.CR_GROUP,
                version=self.CR_VERSION,
                namespace=self.namespace,
                plural=self.CR_PLURAL,
                name=sanitized_name,
            )
            self.custom_api.patch_namespaced_custom_object(
                group=self.CR_GROUP,
                version=self.CR_VERSION,
                namespace=self.namespace,
                plural=self.CR_PLURAL,
                name=sanitized_name,
                body=cr_body,
            )
            if self.verbose:
                logger.info(f"Updated AgentRuntime: {sanitized_name}")
        except Exception:
            self.custom_api.create_namespaced_custom_object(
                group=self.CR_GROUP,
                version=self.CR_VERSION,
                namespace=self.namespace,
                plural=self.CR_PLURAL,
                body=cr_body,
            )
            if self.verbose:
                logger.info(f"Created AgentRuntime: {sanitized_name}")

        endpoint = f"{router_url}/v1/namespaces/{self.namespace}/agent-runtimes/{sanitized_name}/invocations/" if router_url else ""

        return {
            "agent_id": sanitized_name,
            "deployment_name": sanitized_name,
            "namespace": self.namespace,
            "endpoint": endpoint,
        }

    def _sanitize_name(self, name: str) -> str:
        """Sanitize name for Kubernetes resource."""
        name = name.lower()
        name = re.sub(r"[^a-z0-9-]", "-", name)
        name = re.sub(r"-+", "-", name)
        name = name.strip("-")

        if len(name) > 63:
            name = name[:63].rstrip("-")

        return name

    def get_agent_runtime(self, name: str, namespace: str) -> Optional[Dict[str, Any]]:
        """Get AgentRuntime CR by name."""
        try:
            return self.custom_api.get_namespaced_custom_object(
                group=self.CR_GROUP,
                version=self.CR_VERSION,
                namespace=namespace,
                plural=self.CR_PLURAL,
                name=name,
            )
        except Exception as e:
            if self.verbose:
                logger.warning(f"Failed to get AgentRuntime {name}: {e}")
            return None

